# Category: oauth_security

from flask import Flask, request, jsonify
from werkzeug.security import gen_salt
import os

app = Flask(__name__)
auth_codes = {}
tokens = {}
users = {'user1': 'pass1', 'user2': 'pass2'}  # for simplicity, hard-code user credentials here

@app.route('/login')
def login():
    return "Please provide your username and password"

@app.route('/token', methods=['POST'])
def exchange_code():
    data = request.get_json()
    code = data['code']
    
    if code in auth_codes:  # If the code exists
        user_id = auth_codes[code]
        token = gen_salt(24)  # Generate a new token using a secure random function
        
        tokens[token] = user_id  # Store the token for later use
        del auth_codes[code]  # Remove the code after it's used once to ensure uniqueness and prevent replay attacks
        
        return jsonify({"token": token}), 201
    else:
        return jsonify({"error": "invalid_grant"}), 400

@app.route('/code', methods=['POST'])
def generate_code():
    data = request.get_json()
    username = data['username']
    password = data['password']
    
    if users[username] == password:  # Check the provided credentials against stored ones
        code = gen_salt(16)  # Generate a new authorization code using a secure random function
        auth_codes[code] = username  # Store the code for later use
        
        return jsonify({"code": code}), 201
    else:
        return jsonify({"error": "invalid_grant"}), 400
    
if __name__ == '__main__':
    app.run()